import { Fragment } from 'react';
import { Helmet } from 'react-helmet';
import {
  ProjectBackground,
  ProjectContainer,
  ProjectHeader,
  ProjectSection,
  ProjectSectionContent,
  ProjectSectionHeading,
  ProjectSectionText,
  ProjectTextRow,
} from 'components/ProjectLayout';
import Link from 'components/Link';
import usesBackground from 'assets/uses-background.mp4';
import usesBackgroundPlaceholder from 'assets/uses-background-placeholder.jpg';
import prerender from 'utils/prerender';
import { useScrollRestore } from 'hooks';
import Footer from 'components/Footer';
import './index.css';
import { Table, TableCell, TableRow } from 'components/Table';

const Uses = () => {
  useScrollRestore();

  return (
    <Fragment>
      <Helmet>
        <title>Uses | Aleksandr Kartsev</title>
        <meta
          name="description"
          content="A list of hardware and software I use to do my thing"
        />
      </Helmet>
      <ProjectContainer className="uses">
        <ProjectBackground
          src={usesBackground}
          placeholder={usesBackgroundPlaceholder}
          opacity={0.7}
          entered={!prerender}
        />
        <ProjectHeader
          title="Инструменты"
          description="Cписок инструментов, приложений, оборудования и прочего, что я ежедневно использую для проектирования и кодирования."
        />
        <ProjectSection first className="uses__section">
          <ProjectSectionContent>
            <ProjectTextRow width="m">
              <ProjectSectionHeading>Разработка</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>
                   Использую{' '}
                    <Link href="https://code.visualstudio.com/">Visual Studio Code</Link>{' '}, тема Atom One Dark и шрифтом Operator Mono
                  </li>
                  <li>
                    Chrome - мой основной браузер как для разработки, так и для общего использования.
                  </li>
                  <li>
                    <Link href="https://reactjs.org/">React</Link> - библиотека Javascript. Компонентно-ориентированная модель мышления - это
                    первое, что действительно впечатлило меня при знакомстве с React.
                  </li>
                  <li>
                    Для эффектов 3D и шейдеров использую{' '}
                    <Link href="https://threejs.org/">three.js</Link>. С его помощью можно делать действительно мощные вещи.
                  </li>
                  {/* <li>
                    For CSS I've used a myriad pre-processors and css-in-js solutions like
                    styled-components, but these days I'm using vanilla CSS with{' '}
                    <Link href="https://postcss.org/">PostCSS</Link> to get upcoming CSS
                    features today.
                  </li> */}
                  <li>
                    Для Javascript анимаций использую{' '}
                    <Link href="https://popmotion.io/api/">Popmotion Pure 8</Link>, отличная библиотека для spring-анимаций. Для CSS анимаций enter/exit{' '}
                    <Link href="https://reactcommunity.org/react-transition-group/">
                      React Transition Group
                    </Link>
                  </li>
                  <li>
                    Для создания и тестирования компонентов пользовательского интерфейса в изоляции я использую{' '}
                    <Link href="https://storybook.js.org/">Storybook</Link>
                  </li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection first className="uses__section">
          <ProjectSectionContent>
            <ProjectTextRow width="m">
              <ProjectSectionHeading>Дизайн</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>
                    <Link href="https://www.figma.com">Figma</Link> главный инструмент для макетов
                  </li>
                  <li>
                    Вся графика движения создается в Adobe After Effects.
                  </li>
                  <li>
                    Для 3D моделей я использую{' '}
                    <Link href="https://www.blender.org/">Blender</Link>. С версии 2.8 он
                    стал намного проще в использовании и во многих отношениях лучше, чем дорогие
                    3DS Max или Maya.
                  </li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection className="uses__section">
          <ProjectSectionContent>
            <ProjectTextRow stretch width="m">
              <ProjectSectionHeading>Hardware</ProjectSectionHeading>
              <Table>
                <TableRow>
                  <TableCell>
                    <strong>CPU</strong>
                  </TableCell>
                  <TableCell> IntelCore i7-11700KF</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell>
                    <strong>GPU</strong>
                  </TableCell>
                  <TableCell>MSI GeForce RTX 3080Ti</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell>
                    <strong>Memory</strong>
                  </TableCell>
                  <TableCell>16,0 ГБ</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell>
                    <strong>Motherboard</strong>
                  </TableCell>
                  <TableCell>ASUS ROG STRIX Z590-F GAMING</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell>
                    <strong>Monitor</strong>
                  </TableCell>
                  <TableCell>1440p IPS 144hz LG 27GL850</TableCell>
                </TableRow>
                <TableRow>
                  <TableCell>
                    <strong>Laptop</strong>
                  </TableCell>
                  <TableCell>2021 Macbook Air M1</TableCell>
                </TableRow>
              </Table>
            </ProjectTextRow>
          </ProjectSectionContent>
        </ProjectSection>
      </ProjectContainer>
      <Footer />
    </Fragment>
  );
};

export default Uses;
